import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useLocation } from 'react-router-dom';
import Login from './components/Login';
import Register from './components/Register';
import AdminDashboard from './components/AdminDashboard';
import AdminProducts from './components/AdminProducts';
import AdminPartners from './components/AdminPartners';
import PartnerDashboard from './components/PartnerDashboard';
import PartnerProducts from './components/PartnerProducts';
import PartnerSales from './components/PartnerSales';
import PartnerBuyers from './components/PartnerBuyers';
import Sales from './components/Sales';
import { LayoutDashboard, Package, Users, ShoppingCart, LogOut } from 'lucide-react';

const NavLink = ({ to, icon: Icon, children }) => {
  const location = useLocation();
  const isActive = location.pathname === to;
  return (
    <Link to={to} style={{
      display: 'flex', alignItems: 'center', gap: '0.75rem',
      padding: '0.75rem 1rem', color: isActive ? 'white' : '#94a3b8',
      textDecoration: 'none', borderRadius: '8px', marginBottom: '0.25rem',
      background: isActive ? 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)' : 'transparent',
      fontWeight: isActive ? '600' : '500', fontSize: '0.95rem', transition: 'all 0.2s ease'
    }}
    onMouseEnter={(e) => { if (!isActive) { e.currentTarget.style.background = 'rgba(255,255,255,0.07)'; e.currentTarget.style.color = 'white'; } }}
    onMouseLeave={(e) => { if (!isActive) { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = '#94a3b8'; } }}
    >
      <Icon size={20} />{children}
    </Link>
  );
};

function App() {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const tabId = sessionStorage.getItem('tabId');
    const storedUser = sessionStorage.getItem(`user_${tabId}`);
    if (storedUser) setUser(JSON.parse(storedUser));
  }, []);

  const handleLogout = () => {
    const tabId = sessionStorage.getItem('tabId');
    sessionStorage.removeItem(`user_${tabId}`);
    sessionStorage.removeItem(`token_${tabId}`);
    setUser(null);
  };

  return (
    <Router>
      <div style={{ display: 'flex', minHeight: '100vh', background: '#f1f5f9' }}>
        {user && (
          <div style={{
            width: '260px', background: 'linear-gradient(180deg, #1e293b 0%, #0f172a 100%)',
            position: 'fixed', height: '100vh', left: 0, top: 0, zIndex: 1000,
            display: 'flex', flexDirection: 'column'
          }}>
            {/* Logo */}
            <div style={{ padding: '1.75rem 1.5rem 1.25rem', borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
              <h2 style={{
                fontSize: '1.5rem', fontWeight: '800', marginBottom: '0.25rem',
                background: 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)',
                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent'
              }}>Sales ERP</h2>
              <p style={{ fontSize: '0.8rem', color: '#64748b', fontWeight: '500', margin: 0 }}>{user.userRole} Panel</p>
            </div>

            {/* Nav */}
            <nav style={{ padding: '1rem', flex: 1 }}>
              {user?.userRole === 'Admin' && (<>
                <NavLink to="/dashboard" icon={LayoutDashboard}>Dashboard</NavLink>
                <NavLink to="/products" icon={Package}>Products</NavLink>
                <NavLink to="/partners" icon={Users}>Partners</NavLink>
                <NavLink to="/sales" icon={ShoppingCart}>Sales</NavLink>
              </>)}
              {user?.userRole === 'Partner' && (<>
                <NavLink to="/dashboard" icon={LayoutDashboard}>Dashboard</NavLink>
                <NavLink to="/products" icon={Package}>Products</NavLink>
                <NavLink to="/buyers" icon={Users}>My Buyers</NavLink>
                <NavLink to="/sales" icon={ShoppingCart}>Sales</NavLink>
              </>)}
            </nav>

            {/* User + Logout */}
            <div style={{ padding: '1rem', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
              <div style={{
                display: 'flex', alignItems: 'center', gap: '0.75rem',
                padding: '0.75rem', borderRadius: '10px', background: 'rgba(255,255,255,0.05)', marginBottom: '0.75rem'
              }}>
                <div style={{
                  width: '38px', height: '38px', borderRadius: '50%', flexShrink: 0,
                  background: 'linear-gradient(135deg, #f97316 0%, #fb923c 100%)',
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontWeight: '700', fontSize: '1rem', color: 'white'
                }}>
                  {user.fullName?.charAt(0).toUpperCase()}
                </div>
                <div style={{ overflow: 'hidden' }}>
                  <p style={{ fontWeight: '600', fontSize: '0.875rem', color: 'white', margin: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{user.fullName}</p>
                  <p style={{ fontSize: '0.72rem', color: '#64748b', margin: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{user.email}</p>
                </div>
              </div>
              <button onClick={handleLogout} style={{
                width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
                padding: '0.75rem', background: 'rgba(239,68,68,0.1)', color: '#f87171',
                border: '1px solid rgba(239,68,68,0.2)', borderRadius: '8px',
                cursor: 'pointer', fontWeight: '600', fontSize: '0.9rem', transition: 'all 0.2s'
              }}
              onMouseEnter={(e) => { e.currentTarget.style.background = '#ef4444'; e.currentTarget.style.color = 'white'; }}
              onMouseLeave={(e) => { e.currentTarget.style.background = 'rgba(239,68,68,0.1)'; e.currentTarget.style.color = '#f87171'; }}>
                <LogOut size={18} />Logout
              </button>
            </div>
          </div>
        )}

        <div style={{ flex: 1, marginLeft: user ? '260px' : '0', minHeight: '100vh' }}>
          <Routes>
            <Route path="/login" element={!user ? <Login setUser={setUser} /> : <Navigate to="/dashboard" />} />
            <Route path="/register" element={!user ? <Register /> : <Navigate to="/dashboard" />} />
            {user?.userRole === 'Admin' && (<>
              <Route path="/dashboard" element={<AdminDashboard />} />
              <Route path="/products" element={<AdminProducts />} />
              <Route path="/partners" element={<AdminPartners />} />
              <Route path="/sales" element={<Sales />} />
            </>)}
            {user?.userRole === 'Partner' && (<>
              <Route path="/dashboard" element={<PartnerDashboard />} />
              <Route path="/products" element={<PartnerProducts />} />
              <Route path="/buyers" element={<PartnerBuyers />} />
              <Route path="/sales" element={<PartnerSales />} />
            </>)}
            <Route path="/" element={<Navigate to={user ? "/dashboard" : "/login"} />} />
            <Route path="*" element={<Navigate to={user ? "/dashboard" : "/login"} />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
